1	/* Reys hisoboti — Telegram Mini App
2	 * Vanilla JS, no build step. Mobile-first. Light/dark via Telegram theme
3	 * (and prefers-color-scheme when run outside Telegram).
4	 */
5	(function () {
6	  "use strict";
7	
8	  const tg = window.Telegram && window.Telegram.WebApp ? window.Telegram.WebApp : null;
9	  // The SDK defines window.Telegram.WebApp even in a plain browser, where
10	  // initData is empty and MainButton is an invisible no-op. Only treat it as a
11	  // real Telegram client when initData is present.
12	  const inTelegram = !!(tg && tg.initData);
13	
14	  // iOS gets its own (still lightweight) motion curve; Android keeps the current feel.
15	  const isIOS =
16	    (tg && tg.platform === "ios") ||
17	    /iPad|iPhone|iPod/.test(navigator.userAgent) ||
18	    (navigator.platform === "MacIntel" && navigator.maxTouchPoints > 1);
19	  if (isIOS) document.documentElement.classList.add("ios");
20	
21	  const MAX_PHOTOS = 10;
22	  const DEFAULT_TYPES = ["akb", "triton", "izi", "navo", "xabib", "jet", "jon"];
23	
24	  // ---- App state ----
25	  const state = {
26	    activeTab: "report",
27	    reportId: null,
28	    reportName: "",
29	    photos: [], // reys photos { id, file, url }
30	    adjPhotos: [], // adashgan photos
31	    type: "akb",
32	    customTypes: [], // user-added types not yet persisted to inventory
33	    inventory: {}, // tovar_turi -> weight (from server)
34	    coef: { mode: "none", value: 0 }, // mode: none | fixed | custom
35	    weightRaw: "",
36	    adjFrom: "",
37	    adjTo: "",
38	    adjWeightRaw: "",
39	  };
40	
41	  let remember = false;
42	  try { remember = localStorage.getItem("reys-remember") === "1"; } catch (_) {}
43	
44	  // Union of default types, inventory types, and locally-added custom types.
45	  function allTypes() {
46	    const set = new Set(DEFAULT_TYPES);
47	    Object.keys(state.inventory).forEach((t) => set.add(t));
48	    state.customTypes.forEach((t) => set.add(t));
49	    return [...set].sort((a, b) => a.localeCompare(b));
50	  }
51	
52	  const authHeaders = () => (inTelegram ? { "X-Telegram-Init-Data": tg.initData } : {});
53	
54	  let photoSeq = 0;
55	  let sheetOpen = false;
56	  let pendingClose = null; // { done, timer } for an in-flight close animation
57	
58	  // ---- Element refs ----
59	  const $ = (sel) => document.querySelector(sel);
60	  const els = {
61	    tabs: document.querySelectorAll(".tab"),
62	    panels: { report: $("#panel-report"), lost: $("#panel-lost") },
63	    photoGrid: $("#photoGrid"),
64	    photoCounter: $("#photoCounter"),
65	    btnGallery: $("#btnGallery"),
66	    btnCamera: $("#btnCamera"),
67	    inGallery: $("#inGallery"),
68	    inCamera: $("#inCamera"),
69	    camModal: $("#camModal"),
70	    camVideo: $("#camVideo"),
71	    camClose: $("#camClose"),
72	    camFlip: $("#camFlip"),
73	    camShot: $("#camShot"),
74	    camCanvas: $("#camCanvas"),
75	    camZoom: $("#camZoom"),
76	    lightbox: $("#lightbox"),
77	    lightboxImg: $("#lightboxImg"),
78	    lightboxClose: $("#lightboxClose"),
79	    lightboxDel: $("#lightboxDel"),
80	    typeSelect: $("#typeSelect"),
81	    typeValue: $("#typeValue"),
82	    typePencil: $("#typePencil"),
83	    coefChips: $("#coefChips"),
84	    coefCustomWrap: $("#coefCustomWrap"),
85	    coefCustom: $("#coefCustom"),
86	    weight: $("#weight"),
87	    saveBtn: $("#saveBtn"),
88	    // adashgan yuklar (tab 2)
89	    adjFromSelect: $("#adjFromSelect"),
90	    adjFromValue: $("#adjFromValue"),
91	    adjFromBal: $("#adjFromBal"),
92	    adjToSelect: $("#adjToSelect"),
93	    adjToValue: $("#adjToValue"),
94	    adjToBal: $("#adjToBal"),
95	    adjWeight: $("#adjWeight"),
96	    adjSaveBtn: $("#adjSaveBtn"),
97	    balances: $("#balances"),
98	    // activity
99	    activityBtn: $("#activityBtn"),
100	    activityScreen: $("#activityScreen"),
101	    activityClose: $("#activityClose"),
102	    activityList: $("#activityList"),
103	    actDate: $("#actDate"),
104	    actPrev: $("#actPrev"),
105	    actNext: $("#actNext"),
106	    sheet: $("#sheet"),
107	    sheetBackdrop: $("#sheetBackdrop"),
108	    sheetGrip: $("#sheetGrip"),
109	    sheetClose: $("#sheetClose"),
110	    sheetTitle: $("#sheetTitle"),
111	    sheetInput: $("#sheetInput"),
112	    sheetList: $("#sheetList"),
113	    themeColor: $("#themeColor"),
114	    themeBtn: $("#themeBtn"),
115	    toast: $("#toast"),
116	    passkeyAddBtn: $("#passkeyAddBtn"),
117	    passkeyLoginWrap: $("#passkeyLoginWrap"),
118	    passkeyLoginBtn: $("#passkeyLoginBtn"),
119	    loginScreen: $("#loginScreen"),
120	    loginForm: $("#loginForm"),
121	    loginUser: $("#loginUser"),
122	    loginPass: $("#loginPass"),
123	    passToggle: $("#passToggle"),
124	    loginSubmit: $("#loginSubmit"),
125	    loginError: $("#loginError"),
126	    // reports / home
127	    backHomeBtn: $("#backHomeBtn"),
128	    reportName: $("#reportName"),
129	    settingsBtn: $("#settingsBtn"),
130	    homeScreen: $("#homeScreen"),
131	    homeThemeBtn: $("#homeThemeBtn"),
132	    newReportBtn: $("#newReportBtn"),
133	    homeHint: $("#homeHint"),
134	    reportList: $("#reportList"),
135	    nameBackdrop: $("#nameBackdrop"),
136	    nameSheet: $("#nameSheet"),
137	    nameClose: $("#nameClose"),
138	    nameInput: $("#nameInput"),
139	    nameSave: $("#nameSave"),
140	    nameError: $("#nameError"),
141	    setBackdrop: $("#setBackdrop"),
142	    setSheet: $("#setSheet"),
143	    setClose: $("#setClose"),
144	    rememberToggle: $("#rememberToggle"),
145	    // adashgan photos
146	    adjPhotoGrid: $("#adjPhotoGrid"),
147	    adjPhotoCounter: $("#adjPhotoCounter"),
148	    adjBtnGallery: $("#adjBtnGallery"),
149	    adjBtnCamera: $("#adjBtnCamera"),
150	  };
151	
152	  // ---- Theme (admin-controllable: auto / light / dark) ----
153	  const THEME_KEY = "reys-theme";
154	  const THEME_MODES = ["auto", "light", "dark"];
155	  const THEME_ICONS = {
156	    auto: '<svg viewBox="0 0 24 24" class="ic"><path d="M12 2a10 10 0 1 0 0 20V2Z"/></svg>',
157	    light:
158	      '<svg viewBox="0 0 24 24" class="ic"><path d="M12 7a5 5 0 1 0 0 10 5 5 0 0 0 0-10Zm0-6a1 1 0 0 1 1 1v2a1 1 0 1 1-2 0V2a1 1 0 0 1 1-1Zm0 18a1 1 0 0 1 1 1v2a1 1 0 1 1-2 0v-2a1 1 0 0 1 1-1Zm11-7a1 1 0 0 1-1 1h-2a1 1 0 1 1 0-2h2a1 1 0 0 1 1 1ZM5 12a1 1 0 0 1-1 1H2a1 1 0 1 1 0-2h2a1 1 0 0 1 1 1Zm14.07 7.07a1 1 0 0 1-1.41 0l-1.42-1.42a1 1 0 0 1 1.42-1.41l1.41 1.41a1 1 0 0 1 0 1.42ZM7.76 7.76a1 1 0 0 1-1.41 0L4.93 6.34a1 1 0 0 1 1.41-1.41l1.42 1.41a1 1 0 0 1 0 1.42Zm11.31-2.83a1 1 0 0 1 0 1.41l-1.41 1.42a1 1 0 0 1-1.42-1.42l1.42-1.41a1 1 0 0 1 1.41 0ZM7.76 16.24a1 1 0 0 1 0 1.42l-1.42 1.41a1 1 0 0 1-1.41-1.41l1.41-1.42a1 1 0 0 1 1.42 0Z"/></svg>',
159	    dark: '<svg viewBox="0 0 24 24" class="ic"><path d="M21 12.8A9 9 0 1 1 11.2 3a7 7 0 0 0 9.8 9.8Z"/></svg>',
160	  };
161	  const THEME_LABELS = { auto: "Mavzu: Avto", light: "Mavzu: Yorug'", dark: "Mavzu: Tungi" };
162	
163	  let themeMode = "auto";
164	  try { themeMode = localStorage.getItem(THEME_KEY) || "auto"; } catch (_) {}
165	  if (THEME_MODES.indexOf(themeMode) === -1) themeMode = "auto";
166	
167	  function effectiveScheme() {
168	    if (themeMode === "light" || themeMode === "dark") return themeMode;
169	    if (tg && tg.colorScheme) return tg.colorScheme;
170	    return window.matchMedia("(prefers-color-scheme: dark)").matches ? "dark" : "light";
171	  }
172	
173	  function rgbToHex(rgb) {
174	    const m = /rgba?\((\d+),\s*(\d+),\s*(\d+)/.exec(rgb || "");
175	    if (!m) return null;
176	    return "#" + [1, 2, 3].map((i) => Number(m[i]).toString(16).padStart(2, "0")).join("");
177	  }
178	
179	  function syncTelegramChrome() {
180	    let hex = null;
181	    try {
182	      hex = rgbToHex(getComputedStyle(document.body).backgroundColor);
183	      if (els.themeColor && hex) els.themeColor.setAttribute("content", hex);
184	    } catch (_) {}
185	    if (!tg) return;
186	    // Newer clients accept a hex; older accept only keywords; both are wrapped.
187	    try { if (tg.setBackgroundColor) tg.setBackgroundColor(hex || "secondary_bg_color"); } catch (_) {}
188	    try { if (tg.setHeaderColor) tg.setHeaderColor(hex || "secondary_bg_color"); } catch (_) {}
189	  }
190	
191	  function applyTheme() {
192	    const root = document.documentElement;
193	    if (themeMode === "auto") root.removeAttribute("data-theme");
194	    else root.setAttribute("data-theme", themeMode);
195	    root.style.colorScheme = effectiveScheme();
196	    if (els.themeBtn) {
197	      els.themeBtn.innerHTML = THEME_ICONS[themeMode];
198	      els.themeBtn.setAttribute("aria-label", THEME_LABELS[themeMode]);
199	      els.themeBtn.title = THEME_LABELS[themeMode];
200	    }
201	    syncTelegramChrome();
202	  }
203	
204	  function cycleTheme() {
205	    themeMode = THEME_MODES[(THEME_MODES.indexOf(themeMode) + 1) % THEME_MODES.length];
206	    try { localStorage.setItem(THEME_KEY, themeMode); } catch (_) {}
207	    applyTheme();
208	    haptic("select");
209	  }
210	
211	  // ---- Telegram init ----
212	  function initTelegram() {
213	    if (tg) {
214	      tg.ready();
215	      tg.expand();
216	      // Clear any lingering native MainButton (we use a single in-page Save
217	      // button instead — avoids a stale/duplicate Telegram bottom-bar button).
218	      if (tg.MainButton) { try { tg.MainButton.hide(); } catch (_) {} }
219	      // When the user flips their Telegram theme, only follow it in auto mode.
220	      if (tg.onEvent) tg.onEvent("themeChanged", () => { if (themeMode === "auto") applyTheme(); });
221	      if (tg.BackButton) tg.BackButton.onClick(onBack);
222	    }
223	    applyTheme();
224	    if (els.themeBtn) els.themeBtn.addEventListener("click", cycleTheme);
225	    els.saveBtn.addEventListener("click", onSave);
226	    // Inside Telegram the user is authenticated immediately — go to the home list.
227	    if (inTelegram) showHome();
228	  }
229	
230	  // Show the Telegram BackButton whenever we're not at the home root.
231	  function syncBackButton() {
232	    if (!inTelegram || !tg.BackButton) return;
233	    const overlay =
234	      sheetOpen ||
235	      !els.camModal.hidden || !els.lightbox.hidden || !els.activityScreen.hidden ||
236	      !els.nameSheet.hidden || !els.setSheet.hidden;
237	    if (overlay || (state.reportId && els.homeScreen.hidden)) tg.BackButton.show();
238	    else tg.BackButton.hide();
239	  }
240	
241	  function haptic(type) {
242	    if (tg && tg.HapticFeedback) {
243	      if (type === "select") tg.HapticFeedback.selectionChanged();
244	      else tg.HapticFeedback.impactOccurred(type || "light");
245	    }
246	  }
247	
248	  // Telegram BackButton: dismiss the topmost overlay, else go home.
249	  function onBack() {
250	    if (!els.lightbox.hidden) { closeLightbox(); return; }
251	    if (!els.camModal.hidden) { closeCamera(); return; }
252	    if (!els.nameSheet.hidden) { closeNameSheet(); syncBackButton(); return; }
253	    if (!els.setSheet.hidden) { closeSettings(); syncBackButton(); return; }
254	    if (sheetOpen) { closeSheet(); return; }
255	    if (!els.activityScreen.hidden) { closeActivity(); return; }
256	    if (state.reportId && els.homeScreen.hidden) { showHome(); return; }
257	  }
258	
259	  // ---- Tabs ----
260	  function setTab(name) {
261	    state.activeTab = name;
262	    els.tabs.forEach((t) => {
263	      const on = t.dataset.tab === name;
264	      t.classList.toggle("is-active", on);
265	      t.setAttribute("aria-selected", on ? "true" : "false");
266	    });
267	    els.panels.report.classList.toggle("is-active", name === "report");
268	    els.panels.report.hidden = name !== "report";
269	    els.panels.lost.classList.toggle("is-active", name === "lost");
270	    els.panels.lost.hidden = name !== "lost";
271	    // Save only applies to the report tab.
272	    els.saveBtn.style.display = name === "report" ? "" : "none";
273	    haptic("select");
274	  }
275	
276	  els.tabs.forEach((t) => t.addEventListener("click", () => setTab(t.dataset.tab)));
277	
278	  // ---- Photos (two independent sets: reys "photos", adashgan "adjPhotos") ----
279	  let activePk = "photos"; // which set the gallery/camera currently targets
280	  function photoEls(pk) {
281	    return pk === "adjPhotos"
282	      ? { grid: els.adjPhotoGrid, counter: els.adjPhotoCounter, bg: els.adjBtnGallery, bc: els.adjBtnCamera }
283	      : { grid: els.photoGrid, counter: els.photoCounter, bg: els.btnGallery, bc: els.btnCamera };
284	  }
285	
286	  function renderPhotos(pk) {
287	    const e = photoEls(pk);
288	    const arr = state[pk];
289	    e.grid.innerHTML = "";
290	    arr.forEach((p) => {
291	      const cell = document.createElement("div");
292	      cell.className = "thumb";
293	      const img = document.createElement("img");
294	      img.src = p.url;
295	      img.alt = "";
296	      img.addEventListener("click", () => openLightbox(p, pk));
297	      const del = document.createElement("button");
298	      del.className = "thumb__del";
299	      del.type = "button";
300	      del.setAttribute("aria-label", "O'chirish");
301	      del.textContent = "×";
302	      del.addEventListener("click", () => removePhoto(p.id, pk));
303	      cell.append(img, del);
304	      e.grid.appendChild(cell);
305	    });
306	    e.counter.textContent = `${arr.length}/${MAX_PHOTOS}`;
307	    const full = arr.length >= MAX_PHOTOS;
308	    e.bg.disabled = full;
309	    e.bc.disabled = full;
310	  }
311	  function renderAllPhotos() { renderPhotos("photos"); renderPhotos("adjPhotos"); }
312	
313	  function addFiles(fileList, pk) {
314	    const files = Array.from(fileList || []).filter((f) => f.type.startsWith("image/"));
315	    if (!files.length) return;
316	    const arr = state[pk];
317	    const room = MAX_PHOTOS - arr.length;
318	    if (room <= 0) { showToast(`Maksimal ${MAX_PHOTOS} ta rasm`, true); return; }
319	    if (files.length > room) showToast(`Faqat ${room} ta rasm qo'shildi`, true);
320	    files.slice(0, room).forEach((file) => {
321	      arr.push({ id: ++photoSeq, file, url: URL.createObjectURL(file) });
322	    });
323	    renderPhotos(pk);
324	    haptic("light");
325	  }
326	
327	  function removePhoto(id, pk) {
328	    const arr = state[pk];
329	    const idx = arr.findIndex((p) => p.id === id);
330	    if (idx === -1) return;
331	    URL.revokeObjectURL(arr[idx].url);
332	    arr.splice(idx, 1);
333	    renderPhotos(pk);
334	    haptic("light");
335	  }
336	
337	  els.btnGallery.addEventListener("click", () => { activePk = "photos"; els.inGallery.click(); });
338	  els.btnCamera.addEventListener("click", () => { activePk = "photos"; openCamera(); });
339	  els.adjBtnGallery.addEventListener("click", () => { activePk = "adjPhotos"; els.inGallery.click(); });
340	  els.adjBtnCamera.addEventListener("click", () => { activePk = "adjPhotos"; openCamera(); });
341	  els.inGallery.addEventListener("change", (e) => { addFiles(e.target.files, activePk); e.target.value = ""; });
342	  els.inCamera.addEventListener("change", (e) => { addFiles(e.target.files, activePk); e.target.value = ""; });
343	
344	  // ---- Live camera (getUserMedia) ----
345	  // The stream stays alive between shots (only the modal toggles display), so
346	  // the camera permission isn't re-requested on every capture.
347	  let camStream = null;
348	  let camFacing = "environment";
349	  let camZoom = 1; // digital zoom (works on every device)
350	  const hasCamera = !!(navigator.mediaDevices && navigator.mediaDevices.getUserMedia);
351	
352	  async function startStream(facing) {
353	    // Acquire the new stream BEFORE stopping the old one, so a failed flip
354	    // (e.g. device has one camera) leaves the current view intact.
355	    // {exact} forces the requested front/back on Android (ideal is often ignored,
356	    // so the flip / front camera wouldn't actually switch); fall back if absent.
357	    let stream;
358	    try {
359	      stream = await navigator.mediaDevices.getUserMedia({
360	        video: { facingMode: { exact: facing } }, audio: false,
361	      });
362	    } catch (e) {
363	      if (e && e.name === "OverconstrainedError") {
364	        stream = await navigator.mediaDevices.getUserMedia({
365	          video: { facingMode: facing }, audio: false,
366	        });
367	      } else {
368	        throw e;
369	      }
370	    }
371	    stopStream();
372	    camStream = stream;
373	    camFacing = facing;
374	    els.camVideo.srcObject = stream;
375	    try { await els.camVideo.play(); } catch (_) {} // WebViews need an explicit play()
376	    setZoom(1);
377	  }
378	  function stopStream() {
379	    if (camStream) { camStream.getTracks().forEach((t) => t.stop()); camStream = null; }
380	  }
381	
382	  function setZoom(z) {
383	    camZoom = Math.max(1, Math.min(z, 5));
384	    els.camVideo.style.transform = `scale(${camZoom})`;
385	    els.camZoom.textContent = `${camZoom.toFixed(1)}x`;
386	  }
387	
388	  async function openCamera() {
389	    if (state[activePk].length >= MAX_PHOTOS) { showToast(`Maksimal ${MAX_PHOTOS} ta rasm`, true); return; }
390	    if (!hasCamera) { els.inCamera.click(); return; } // fallback to file-input capture
391	    els.camModal.hidden = false;
392	    document.body.classList.add("locked");
393	    syncBackButton();
394	    try {
395	      if (!camStream) await startStream(camFacing);
396	      else { try { await els.camVideo.play(); } catch (_) {} } // resume the kept-alive stream
397	    } catch (e) {
398	      closeCamera();
399	      const n = e && e.name;
400	      if (n === "NotAllowedError" || n === "NotFoundError" || n === "NotReadableError") els.inCamera.click();
401	      else showToast("Kamera ochilmadi", true);
402	    }
403	  }
404	
405	  function closeCamera() {
406	    els.camModal.hidden = true;
407	    document.body.classList.remove("locked");
408	    syncBackButton();
409	  }
410	
411	  function capturePhoto() {
412	    const v = els.camVideo;
413	    if (!v.videoWidth) return;
414	    // Crop the centre region to match the on-screen digital zoom.
415	    const sw = v.videoWidth / camZoom;
416	    const sh = v.videoHeight / camZoom;
417	    const sx = (v.videoWidth - sw) / 2;
418	    const sy = (v.videoHeight - sh) / 2;
419	    const canvas = els.camCanvas;
420	    canvas.width = Math.round(sw);
421	    canvas.height = Math.round(sh);
422	    canvas.getContext("2d").drawImage(v, sx, sy, sw, sh, 0, 0, canvas.width, canvas.height);
423	    const pk = activePk;
424	    canvas.toBlob((blob) => {
425	      if (blob) {
426	        const file = new File([blob], `cam_${blob.size}_${state[pk].length}.jpg`, { type: "image/jpeg" });
427	        addFiles([file], pk);
428	      }
429	      closeCamera(); // hide modal, keep stream alive for the next shot
430	    }, "image/jpeg", 0.92);
431	  }
432	
433	  async function flipCamera() {
434	    const next = camFacing === "environment" ? "user" : "environment";
435	    try { await startStream(next); } catch (_) { showToast("Kamera almashtirilmadi", true); }
436	  }
437	
438	  // Pinch-to-zoom.
439	  let pinch = null;
440	  const touchDist = (t) => Math.hypot(t[0].clientX - t[1].clientX, t[0].clientY - t[1].clientY);
441	  els.camModal.addEventListener("touchstart", (e) => {
442	    if (e.touches.length === 2) pinch = { d: touchDist(e.touches), z: camZoom };
443	  }, { passive: true });
444	  els.camModal.addEventListener("touchmove", (e) => {
445	    if (pinch && e.touches.length === 2) setZoom(pinch.z * (touchDist(e.touches) / pinch.d));
446	  }, { passive: true });
447	  els.camModal.addEventListener("touchend", () => { pinch = null; });
448	
449	  els.camShot.addEventListener("click", capturePhoto);
450	  els.camClose.addEventListener("click", closeCamera);
451	  els.camFlip.addEventListener("click", flipCamera);
452	  els.camZoom.addEventListener("click", () => setZoom(camZoom >= 3 ? 1 : Math.floor(camZoom) + 1));
453	  window.addEventListener("pagehide", stopStream);
454	
455	  // ---- Photo lightbox ----
456	  let lightboxId = null;
457	  let lightboxPk = "photos";
458	  function openLightbox(photo, pk) {
459	    lightboxId = photo.id;
460	    lightboxPk = pk || "photos";
461	    els.lightboxImg.src = photo.url;
462	    els.lightbox.hidden = false;
463	    document.body.classList.add("locked");
464	    syncBackButton();
465	  }
466	  function closeLightbox() {
467	    els.lightbox.hidden = true;
468	    els.lightboxImg.src = "";
469	    lightboxId = null;
470	    document.body.classList.remove("locked");
471	    syncBackButton();
472	  }
473	  function deleteFromLightbox() {
474	    if (lightboxId != null) removePhoto(lightboxId, lightboxPk);
475	    closeLightbox();
476	  }
477	  els.lightbox.addEventListener("click", (e) => { if (e.target === els.lightbox) closeLightbox(); });
478	  els.lightboxClose.addEventListener("click", closeLightbox);
479	  els.lightboxDel.addEventListener("click", deleteFromLightbox);
480	
481	  // ---- Reports (home) ----
482	  function confirmDialog(msg) {
483	    return new Promise((resolve) => {
484	      if (inTelegram && tg.showConfirm) tg.showConfirm(msg, (ok) => resolve(!!ok));
485	      else resolve(window.confirm(msg));
486	    });
487	  }
488	
489	  function reportItem(rep) {
490	    const li = document.createElement("li");
491	    li.className = "report-item";
492	    const main = document.createElement("div");
493	    main.className = "report-item__main";
494	    const name = document.createElement("div");
495	    name.className = "report-item__name";
496	    name.textContent = rep.name;
497	    const sub = document.createElement("div");
498	    sub.className = "report-item__sub";
499	    sub.textContent = `${fmtTs(rep.created_at)} · ${rep.entries || 0} yozuv`;
500	    main.append(name, sub);
501	    const del = document.createElement("button");
502	    del.className = "report-item__del";
503	    del.type = "button";
504	    del.setAttribute("aria-label", "O'chirish");
