651	  function closeSheet() {
652	    if (!sheetOpen) return;
653	    sheetOpen = false;
654	    els.sheetInput.blur();
655	
656	    els.sheetBackdrop.classList.add("is-closing");
657	    els.sheet.style.transition = "transform 0.22s cubic-bezier(0.2,0.8,0.2,1)";
658	    els.sheet.style.transform = "translateY(100%)";
659	
660	    let finished = false;
661	    const onEnd = (e) => { if (e.propertyName === "transform") done(); };
662	    const done = () => {
663	      if (finished) return;
664	      finished = true;
665	      if (pendingClose) { clearTimeout(pendingClose.timer); pendingClose = null; }
666	      els.sheet.removeEventListener("transitionend", onEnd);
667	      els.sheet.hidden = true;
668	      els.sheetBackdrop.hidden = true;
669	      els.sheetBackdrop.classList.remove("is-closing");
670	      els.sheet.style.transition = "";
671	      els.sheet.style.transform = "";
672	    };
673	    els.sheet.addEventListener("transitionend", onEnd);
674	    pendingClose = { done, timer: setTimeout(done, 280) }; // fallback if transitionend doesn't fire
675	
676	    syncBackButton();
677	  }
