1193	  // ---- WebAuthn helpers ----
1194	  const _b64uToBuf = (s) => {
1195	    s = s.replace(/-/g, "+").replace(/_/g, "/");
1196	    s += "=".repeat((4 - (s.length % 4)) % 4);
1197	    const bin = atob(s);
