(() => {
  const $ = (s) => document.getElementById(s);
  const st = () => ({ home:!$('homeScreen').hidden, menu:!$('menuScreen').hidden, locked:document.body.classList.contains('locked') });
  const steps = [];
  steps.push({ at:'menu shown', ...st() });
  $('menuDistBtn').click();                       // Kargolarga tarqatish → work area
  steps.push({ at:'after Kargolarga tarqatish', ...st() });
  $('backHomeBtn').click();                        // topbar back → menu
  steps.push({ at:'after topbar back', ...st() });
  $('menuBackBtn').click();                         // menu back → home
  steps.push({ at:'after menu back', ...st() });
  return steps;
})();

