(() => {
  const $ = (s) => document.getElementById(s);
  ['loginScreen','homeScreen','activityScreen'].forEach(id => { const e=$(id); if(e) e.hidden=true; });
  // start at report menu
  $('menuScreen').hidden = false; $('obshiyScreen').hidden = true; $('topScreen').hidden = true;
  $('menuTitle').textContent = 'Reys #14';
  const vis = () => ({menu:!$('menuScreen').hidden, obshiy:!$('obshiyScreen').hidden, top:!$('topScreen').hidden});
  const steps = [];
  steps.push({at:'menu', ...vis()});
  $('menuTotalBtn').click();              // Obshiy ves
  steps.push({at:'after Obshiy ves', ...vis()});
  $('obshiyTopBtn').click();              // Top
  steps.push({at:'after Top', ...vis()});
  // layout of top form controls
  const rw = (id)=>Math.round($(id).getBoundingClientRect().width);
  return {steps, layout:{code:rw('topCode'), pencil:rw('topCodePencil'), weight:rw('topWeight'), save:rw('topSave')}};
})();

