input.expression:
(() => {
  const $ = (s) => document.getElementById(s);
  const fire = (el, v) => { el.value = v; el.dispatchEvent(new Event('input', {bubbles:true})); return el.value; };
  const out = {};
  // 1) karobka kodi numeric-only (default)
  out.codeNumeric = fire($('topCode'), '12a3b4-5');           // expect "12345"
  // 2) pencil → free text
  $('topCodePencil').click();
  out.pencilOnClass = $('topCodePencil').className.includes('is-on');
  out.codeInputMode = $('topCode').inputMode;
  out.codeFree = fire($('topCode'), 'AB-12/x');               // expect unchanged
  // 3) pencil back → numeric strips existing
  $('topCodePencil').click();
  out.codeReStripped = $('topCode').value;                    // expect "12"
  out.codeInputMode2 = $('topCode').inputMode;
  // 4) weight comma→dot + single dot
  out.weightComma = fire($('topWeight'), '12,5');             // expect "12.5"
  out.weightMultiDot = fire($('topWeight'), '1.2.3');         // expect "1.23"
  return out;
})();

(() => {
  const $ = (s) => document.getElementById(s);
  const fire = (el, v) => { el.value = v; el.dispatchEvent(new Event('input', {bubbles:true})); };
  const toast = () => ({text:$('toast').textContent, err:$('toast').className.includes('toast--err'), hidden:$('toast').hidden});
  const out = {};
  // valid save
  fire($('topCode'), '4457'); fire($('topWeight'), '23,4');
  $('topSave').click();
  out.afterValidSave = { toast: toast(), code: $('topCode').value, weight: $('topWeight').value };
  // invalid: empty code
  $('topSave').click();
  out.afterEmptyCode = { toast: toast() };
  // invalid: code but bad weight
  fire($('topCode'), '99'); fire($('topWeight'), '0');
  $('topSave').click();
  out.afterBadWeight = { toast: toast() };
  return out;
})();

