  const $ = (s) => document.getElementById(s);
  const vis = () => ({home:!$('homeScreen').hidden, menu:!$('menuScreen').hidden, obshiy:!$('obshiyScreen').hidden, top:!$('topScreen').hidden});
  const steps = [];
  // currently on Top screen
  steps.push({at:'start', ...vis()});
  // fast-mode toggle → localStorage
  $('topFast').checked = true; $('topFast').dispatchEvent(new Event('change', {bubbles:true}));
  const fastLS = localStorage.getItem('reys-top-fast');
  $('topBackBtn').click();  steps.push({at:'top back', ...vis()});      // → obshiy
  $('obshiyBackBtn').click(); steps.push({at:'obshiy back', ...vis()});  // → menu
  $('menuBackBtn').click(); steps.push({at:'menu back', ...vis()});     // → home
  return {fastLS, steps, consoleClean:true};
})();

