  animation: thumbIn 0.18s var(--ease);
}
.entry-card__code { font-size: 16px; font-weight: 700; color: var(--text); word-break: break-all; }
.entry-card__sub { font-size: 12px; color: var(--hint); margin-top: 2px; }
