  if (e.from && e.to) parts.push(`${e.from} → ${e.to}`);
  else if (e.type) parts.push(e.type + (e.coefficient ? ` · koef ${e.coefficient}` : ""));
  else if (e.code) parts.push(e.code);
  parts.push(fmtKg(e.weight));
  parts.push(fmtTs(e.ts / 1000));
  return parts.join(" · ");
}

function lbShow() {
  const items = lbItems();
  if (!items.length) { closeLightbox(); return; }
  lb.i = Math.min(Math.max(lb.i, 0), items.length - 1);
  if (lbTempUrl) { URL.revokeObjectURL(lbTempUrl); lbTempUrl = null; }
  if (lb.mode === "form") {
    els.lightboxImg.src = items[lb.i].url;
  } else {
    lbTempUrl = URL.createObjectURL(items[lb.i]);
    els.lightboxImg.src = lbTempUrl;
  }
  const many = items.length > 1;
  els.lightboxCount.hidden = !many;
  els.lightboxCount.textContent = `${lb.i + 1}/${items.length}`;
  els.lightboxPrev.hidden = !many;
  els.lightboxNext.hidden = !many;
  els.lightboxPrev.disabled = lb.i === 0;
  els.lightboxNext.disabled = lb.i === items.length - 1;
  const cap = lb.mode === "entry" ? lb.caption : "";
