      renderBalances();
      renderAdjust();
    } catch (e) {
      showToast(e.message || "O'chirib bo'lmadi", true);
      return;
    }
  }
  const list = state.entries[sec];
  const i = list.indexOf(entry);
  if (i === -1) return;
  list.splice(i, 1);
